--
-- Дамп данных таблицы `heroes`
--

INSERT INTO `heroes` (`id`, `name`, `info`, `photo`) VALUES
(1, 'Alchemist', '\r\nПолучает больше золота за руны богатства и убийство существ\r\nВырвавшись из заточения при помощи огра, Раззил Темновар взялся за поиски новых образцов для исследования трансмутации. Используя свои обширные познания в алхимии, Раззил извлекает дополнительное золото из крипов с помощью Greevil\'s Greed, а также может создать целую лужу токсичной Acid Spray, разъедающую вражеские латы. Алхимик, сидя на спине своего верного товарища, способен сварить крайне нестабильную Unstable Concoction, которая усиливается с каждой секундой и взрывается при попадании во врага. В случае крайней нужды, Раззил вливает в своего компаньона непонятное зелье, провоцируя огра впасть в Chemical Rage. Зелье вызывает сверхъестественную скорость атаки, сверхвысокую скорость регенерации здоровья и крайне приятный фиолетовый оттенок кожи.', 'heroes/Alchemist_icon.webp'),
(2, 'Abaddon', 'Защищает союзников или себя самого\r\nРод Аверно питает купель — разлом в земной тверди, который испускает загадочную энергию на протяжении поколений. Каждого новорождённого семьи окунают в этот тёмный туман, даруя тем самым связь с их землёй и её загадочной силой. Дети растут с непреклонной верой в защиту семейных ценностей и традиций земли, но на самом деле они охраняют саму купель, истинные намерения которой неизвестны.\r\n\r\nКогда новорождённый Abaddon проходил обряд крещения, что-то пошло не так. В глазах малыша сверкнула искра разума, испугавшая всех присутствовавших и заставившая жрецов шептаться. Его растили, дабы он пошёл по пути всех отпрысков рода: война и защита родины во главе армии. Но сам Abaddon уделял этому не так много внимания. Пока другие тренировались в обращении с оружием, он медитировал у купели. Он глубоко вдыхал тёмный туман, учась быть единым с той силой, что протекала глубоко под землёй его дома. В конечном счёте он стал порождением чёрного тумана.\r\n\r\nРод Аверно неодобрительно отнёсся к такому решению, обвиняя его в пренебрежении обязанностями. Но все эти обвинения прекратились, когда Abaddon вступил в свою первую битву и показал ту обретённую власть над жизнью и смертью, о которой другие члены рода не могли и мечтать.\r\nЗакрыть историю\r\nAbaddon, способный лечиться за счёт вражеских атак, может пережить почти любое нападение. Он всегда готов вклиниться в битву, закрывая союзников щитом и запуская обоюдоострые витки мглы, которыми он увечит врагов и исцеляет товарищей.', 'heroes/Abadon.jpg'),
(3, 'Axe', 'Провоцирует врагов, заставляя их атаковать его\r\nОдин за другим солдаты Красного тумана пали. Одни в погибли битвах, другие стали жертвами амбиций Могул Хана. В какой-то момент самопровозглашенный генерал обнаружил, что командовать ему больше некем. «Неважно», — подумал Axe. «Войско из одного солдата — лучшая возможная армия». Врываясь в схватку, Могул Хан издает свой Berserker\'s Call, обращая против себя мечи всех врагов вокруг, заставляя их атаковать себя. Принимая удары, Axe контратакует врагов, рассекая вокруг себя топором в смертельном Counter Helix, с легкостью одолевая всю собравшуюся кругом толпу. Ускользнувших от Axe терзает нескончаемая Battle Hunger — жажда битвы, которую нельзя утолить никоим способом, кроме смерти, чужой или своей. Тех немногих, кто выживает после схватки, Могул Хан отправляет на тот свет Culling Blade, не останавливаясь, пока не останется никого.', 'heroes/Axe_icon.webp'),
(4, 'Bristleback', '\r\nПолучает меньше урона, отвернувшись от врагов\r\nВ сражении Bristleback совсем не против подставить врагам спину. Уменьшая весь урон, который ему наносят сзади и сбоку, он безрассудно бросается в бой и обдаёт врагов смертоносными иглами и замедляющими соплями.', 'heroes/Bristleback_icon.webp'),
(5, 'Meepo', 'Пятеро сильнее одного\r\nПризвав до пяти своих полноценных копий, Meepo способен сражаться на всех фронтах одновременно. Он распределяет своих клонов по полю боя и, заметив врага, приковывает его к земле, со взрывом телепортирует к себе остальные копии и добивает истощённую жертву.', 'heroes\\Meepo_icon.webp'),
(6, 'Disruptor', 'Ловит врагов в свой статический шторм, накладывающий безмолвие\r\nC нагорий Друуда Грозодел, известный как Disruptor, спустился верхом на своем страйдере, чтобы встретится с теми, кто угрожает древним землям Оглоди. На спине он держит устройство, позволяющее призывать Thunder Strike с небес. Грозодел с помощью Glimpse переносит вражеских героев к месту, где они были ранее, и сооружает вокруг Kinetic Field, запирая их в круглом барьере. Магические испарения внутри Static Storm Disruptor ловят противников, не оставляя им вариантов, кроме как ожидать собственной гибели.', 'heroes\\Disruptor_icon.webp'),
(7, 'Broodmother', 'Охотится на врагов со своей паучьей армией\r\nСкользя по своей паутине, Broodmother взращивает армию пауков, которые вместе с её командой наступают на базу врага. Если на пути встречается жертва, паучиха присоединяется к своим отпрыскам и нападает, замедляя врагов ядовитыми укусами и утоляя свой животный голод.', 'heroes\\Broodmother_icon.webp'),
(8, 'Io', 'Связывается с союзниками, чтобы усилить их\r\nIo мастерски повышает эффективность союзников. Связав себя с кем-нибудь из них, он ускоряет свою цель, а враги между ним и его товарищем замедляются. Способность телепортироваться вместе с союзником может многократно увеличить потенциал и без того смертоносного героя.', 'heroes\\Io_icon.webp'),
(9, 'Phantom Lancer', 'Создаёт иллюзии, которые помогают обхитрить или сразить врага Phantom Lancer уничтожает противников бесконечным запасом своих клонов. Его армия иллюзий сметает вражеские силы и укрепления шквалом молниеносных ударов, а заодно запутывает противника, позволяя избежать опасности.', 'heroes/1771870814_Phantom_Lancer_icon.webp');

