CREATE TABLE `items` (
  `id` int NOT NULL,
  `name` varchar(255) NOT NULL,
  `info` text NOT NULL,
  `photo` varchar(255) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Дамп данных таблицы `items`
--

INSERT INTO `items` (`id`, `name`, `info`, `photo`) VALUES
(1, 'Divine Rapier', 'Divine Rapier — это предмет, который можно купить в домашней лавке, в разделе оружие. При этом его сборка требует предметов из потайной лавки.\r\nЕсли герой, владеющий Divine Rapier, умирает без наличия воскрешения — она выпадает.\r\nВыпавшая Divine Rapier не может быть уничтожена или продана.\r\nDivine Rapier нельзя переложить в ранец.\r\nВ отличии от других собираемых предметов, Divine Rapier нельзя разобрать в течение 10 секунд после сборки.\r\nКурьер может купить и принести Divine Rapier, но не может подобрать предмет с земли.\r\nВыпавшую Divine Rapier может подобрать любой герой. В зависимости от того кто ее подобрал, она меняется.', 'items/Divine_Rapier_icon.webp'),
(2, 'Butterfly', 'Butterfly — это предмет, который можно купить в домашней лавке, в разделе оружие. При этом его сборка требует предметов из потайной лавки.\r\n\r\nАтрибуты этого предмета дают следующие дополнительные бонусы:\r\n35 скорости атаки и 5,83 основной брони.\r\n35 основного урона от атаки героям Agility attribute symbol ловкости.\r\n24,5 основного урона от атаки Universal attribute symbol универсальным героям.\r\nУклонение сочетается по закону убывающей полезности с другими источниками уклонения.\r\nУвеличивает выживаемость против физических атак для большинства героев на 53.85%.\r\nУклонение использует псевдослучайное распределение.', 'items/Butterfly_icon.webp'),
(3, 'Heart of Tarrasque', 'Heart of Tarrasque — это предмет, находящийся в домашней лавке, в разделе броня. Однако, его сборка требует предметов из потайной лавки.\r\n\r\nАтрибуты этого предмета дают следующие дополнительные бонусы:\r\n880 здоровья и 4 восстановления здоровья.\r\n40 основного урона от атаки героям Strength attribute symbol силы.\r\n28 основного урона от атаки Universal attribute symbol универсальным героям.\r\nБонус к восстановлению здоровья от макс. здоровья от нескольких Heart of Tarrasque не складывается.\r\nМожет восстановить до 96% от максимального здоровья носителя в минуту.\r\nМожет полностью восстановить здоровье носителя за 62,5 сек.', 'items/Heart_of_Tarrasque_icon.webp'),
(4, 'Glimmer Cape', 'Glimmer Cape это предмет, покупаемый в домашней лавке, в разделе магия.\r\n\r\nСочетается по закону убывающей полезности с другими источниками сопротивления магии.\r\nУвеличивает общее сопротивление магии героев до 43,75%.\r\nКаждые 10 очков Intelligence attribute symbol интеллекта в произведении с этим источником увеличивают общее сопротивление магии на 0,75% [?].', 'items/Glimmer_Cape_icon.webp'),
(5, 'Tranquil Boots', 'Tranquil Boots — это предмет, который можно приобрести в домашней лавке, в разделе поддержка.\r\nБонусы к скорости передвижения от нескольких пар сапог не сочетаются.\r\nСочетается со всеми другими бонусами к скорости передвижения.\r\nВосстановление здоровья от нескольких Tranquil Boots полностью сочетается.\r\nСпособность', 'items/Tranquil_Boots_29_icon.webp'),
(6, 'Gem of True Sight', 'Gem of True Sight — это предмет, который можно купить в домашней лавке, в разделе разное.\r\n\r\nЭтот предмет выпадает, когда носитель умирает, если только у него нет воскрешения.\r\nGem of True Sight нельзя переложить в ранец.', 'items/Gem_of_True_Sight_icon.webp'),
(7, 'Power Treads', 'Power Treads — это предмет, который можно купить в домашней лавке, в разделе аксессуары.\r\nБонусы к скорости передвижения от нескольких пар сапог не сочетаются, приоритет имеют сапоги с высшим значением.\r\nСочетается со всеми другими бонусами к скорости передвижения.\r\nБонусы к скорости атаки от нескольких Power Treads не сочетаются.\r\nЕсть 3 способа собрать Power Treads. В зависимости от того какой предмет был выбран, разнится изначальное состояние Strength attribute symbol / Agility attribute symbol / Intelligence attribute symbol атрибута сапог. Состояние можно свободно менять с помощью  Switch Attribute после покупки.\r\nКогда находится в списке быстрых покупок, то компоненты сборки предмета основываются на основном атрибуте героя.\r\nРазборка Power Treads возвращает предметы которые изначально использовались для сборки. Она не основывается на текущем выбранном атрибуте.', 'items/Power_Treads_icon.webp'),
(8, 'Mask of Madness', 'Mask of Madness — это предмет, который можно купить в домашней лавке в разделе аксессуары.\r\n\r\nДает 100 к скорости атаки и 25 к скорости передвижения, но уменьшает броню на 8 и запрещает использовать заклинания. Длится 6 секунд.', 'items/Mask_of_Madness_icon.webp'),
(9, 'Boots of Travel', 'Boots of Travel — это предмет, который можно купить в домашней лавке, в разделе аксессуары. Его можно улучшить, купив рецепт второй раз.\r\nУлучшение предмета усиливает пассивную способность улучшение Town Portal Scroll. Можно улучшить лишь один раз. \r\n1 уровень - телепортирует вас на крипов\r\n2 уровень - телепортирует вас на героев', 'items/Boots_of_Travel_2_icon.webp'),
(10, 'Guardian Greaves', 'Guardian Greaves это предмет, покупаемый в домашней лавке, в разделе поддержка.\r\nДополнительная скорость передвижения от нескольких пар сапогов не суммируется.\r\nСкладывается с другими бонусами скорости передвижения.', 'items\\Guardian_Greaves_icon.webp'),
(11, 'Parasma', 'Parasma — предмет, который можно купить в домашней лавке, в разделе оружие. При этом его сборка требует предметов из потайной лавки.\r\n\r\nАтрибуты этого предмета дают следующие дополнительные бонусы:\r\n480 маны, 2 восстановления маны и 4% прямого базового сопротивления магии.\r\n40 основного урона от атаки героям Intelligence attribute symbol интеллекта.\r\n28 основного урона от атаки Universal attribute symbol универсальным героям.\r\nБонус к скорости снаряда действует только на снаряды атаки.', 'items\\Parasma_icon.webp'),
(12, 'Hand of Midas', 'Hand of Midas — это предмет, который можно купить в домашней лавке, в разделе аксессуары.\r\n\r\nTransmute целиком заменяет награду в золоте за существо, так что стандартная награда за существо не даётся.\r\nЭффективное получаемое золото определяется как: ФОРМУЛА160 - НаградаЗаСуществоЗолотом.\r\nИз-за этой особенности, при использовании на больших существ, герой теряет почти половину от награды за существо в золоте Золото, но получает вдвое больше опытаXP.\r\nДля большей информации, смотрите сюда.', 'items/Hand_of_Midas_icon.webp'),
(13, 'Moon Shard', 'Moon Shard — это предмет, который можно купить в домашней лавке, в разделе аксессуары. При этом его сборка требует предметов из потайной лавки.\r\n\r\nНесколько Moon Shard не складываются в инвентаре. Каждый купленный предмет занимает отдельный слот.\r\nСкорость атаки от нескольких предметов складывается.', 'items/Moon_Shard_icon.webp');

